var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"오르카 씨!! 괜찮아요? 눈 좀 떠 봐요!","JPN":"オルカさん！！　大丈夫ですか？　目を開けてください！","ENG":"Orca!! Are you all right?! Wake up!","TWN":"奧爾卡！！你沒事吧？你醒一醒！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"안심하시길. 당분간 안정을 취하면 깨어나실 겁니다.","JPN":"ご安心を。しばらくすると目覚めるでしょう。","ENG":"Don't worry. She'll be fine if you let her rest for a while.","TWN":"請放心，她很快就會醒來的。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만 최근 뵈었을 때보다 놀랄 만큼 강해지셨군요. 그 자 말대로.","JPN":"ですが、この前会った時より驚くほどに強くなられましたね。あの者の言うとおり。","ENG":"But she's become much stronger since the last time I saw her. Just like he said.","TWN":"不過他說的沒錯，確實比最近一次看到時更厲害。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그 자라니……? 그 사람이 베로니카 씨에게 이런 짓을 하라고 요구한 건가요?","JPN":"あの者……？　その人がベロニカさんにこんなことをするよう仕向けたのですか？","ENG":"Who are you talking about...? Is he the person who asked you to do this, Miss Veronica?","TWN":"他是誰……？是那個人要求你做這種事的嗎？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"아뇨. 사장님을 찾아뵈러 온 건 순전히 제 판단이랍니다.","JPN":"いいえ。社長を訪ねたのはひとえに私の判断です。","ENG":"No. It was my decision to come and see Boss.","TWN":"不，來找老闆是我個人的決定。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"이만 자리를 피해 주세요. 여기 오래 머무르시면 위험한 일에 휘말릴 수 있습니다.","JPN":"もうこの場からお離れください。長くとどまれば危険なことに巻き込まれるかもしれません。","ENG":"Now, please leave the area. You'll also be in danger if you stay here for too long.","TWN":"請趕緊離開，你若繼續待在這裡，恐怕會捲入危險之中。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"기다려요, 베로니카 씨!","JPN":"待ってください、ベロニカさん！","ENG":"Miss Veronica, wait!","TWN":"等一下，貝洛妮卡！"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"뭔가 협박당하고 계신 거라면 사장님께서 도와 주실 거예요.","JPN":"誰かに脅迫されているのでしたら、社長が助けてくださるはずです。","ENG":"If you're being threatened, I'm sure Boss can help you.","TWN":"是不是有人威脅你？老闆一定會幫你的。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그러니까 솔직하게 말씀해 주세요. 모네 양이 이 일을 알면 슬퍼하지 않겠어요?","JPN":"だからありのままに話してください。モネさんがこのことを知ったら悲しむと思いませんか？","ENG":"So please, just tell me the truth. Think about how Mone would feel is she heard about this.","TWN":"你就老實說吧。況且莫妮要是知道這件事，你覺得她不會難過嗎？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"……저는 이만 집무실로 가야 하니, 오르카 씨를 부탁드리겠습니다.","JPN":"……私はもう執務室へ向かわないといけませんので、オルカさんをよろしくお願いいたします。","ENG":"...I must head to the office now. Please take care of Orca for me.","TWN":"……我現在要去辦公室，奧爾卡就麻煩了。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그럼 모쪼록, 평안하시길.","JPN":"それでは、どうかご自愛ください。","ENG":"Then, I bid you farewell.","TWN":"請務必要平安無事。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"요점만 말씀하세요. 제게 뭘 원하시는 거죠?","JPN":"要点だけお話しください。私に何を求めているのですか？","ENG":"Just cut to the chase. What do you want from me?","TWN":"請說重點吧，你想要我做什麼？"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"간단해. 아버지의 집무실에 숨겨진 통로가 있을 걸세.","JPN":"簡単なことさ。父の執務室に、隠し通路があるはずだ。","ENG":"It's simple. There's a hidden pathway in Father's office.","TWN":"很簡單，爸爸的辦公室裡應該有個秘密通道。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"주인님을 아버지라고 부를 수 있는 분은 제가 아는 한 한 분밖에 없습니다.","JPN":"ご主人様を父と呼べる方は、私の知っている限りお一人だけです。","ENG":"There's only one person I know who can say Father to Master.","TWN":"能夠稱呼主人爸爸的，據我所知就只有一位。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"하하, 야속하군. 마음에 들진 않아도 일단은 한 핏줄이나 마찬가지인데.","JPN":"はは、悲しいな。気に入らなくても一応は同じ血筋なんだが。","ENG":"Haha! How heartless. But even if you don't like it, I am still his flesh and blood.","TWN":"哈哈，真是冷血，不過就算你不喜歡，但血脈相連是事實。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};